# lib/my_app_web/plugs/xml_parser.ex
defmodule MyAppWeb.Plugs.XMLParser do
  import Plug.Conn

  def init(opts), do: opts

  def call(conn, _opts) do
    case read_body(conn) do
      {:ok, body, conn} ->
        assign(conn, :raw_xml_body, body)

      {:more, _partial, conn} ->
        conn
        |> put_status(413)
        |> Phoenix.Controller.json(%{error: "Request body too large"})
        |> halt()

      {:error, _reason} ->
        conn
        |> put_status(400)
        |> Phoenix.Controller.json(%{error: "Failed to read request body"})
        |> halt()
    end
  end
end

# lib/my_app_web/xml/safe_parser.ex
defmodule MyAppWeb.XML.SafeParser do
  @moduledoc """
  Secure XML parser that disables external entities to prevent XXE attacks.
  Uses :xmerl under the hood with safe options.
  """

  import SweetXml

  @doc """
  Safely parses XML string with external entities DISABLED.
  Returns {:ok, parsed_doc} or {:error, reason}.
  """
  def safe_parse(xml_string) when is_binary(xml_string) do
    try do
      # Use xmerl options to disable external entities and DTD processing
      # This prevents XXE (XML External Entity) attacks
      parsed =
        xml_string
        |> String.trim()
        |> parse(
          dtd: :none,
          quiet: true
        )

      {:ok, parsed}
    rescue
      e ->
        {:error, "XML parsing failed: #{inspect(e)}"}
    catch
      :exit, reason ->
        {:error, "XML parsing error: #{inspect(reason)}"}
    end
  end

  @doc """
  Safely extracts values using xpath from a pre-parsed document.
  """
  def safe_xpath(doc, xpath_expr) do
    try do
      result = SweetXml.xpath(doc, xpath_expr)
      {:ok, result}
    rescue
      e -> {:error, "XPath evaluation failed: #{inspect(e)}"}
    end
  end
end

# lib/my_app_web/controllers/soap_controller.ex
defmodule MyAppWeb.SoapController do
  use MyAppWeb, :controller

  import SweetXml
  alias MyAppWeb.XML.SafeParser

  @doc """
  Handles incoming SOAP XML requests securely.
  """
  def handle(conn, _params) do
    raw_xml = conn.assigns[:raw_xml_body]

    with {:ok, doc} <- SafeParser.safe_parse(raw_xml),
         {:ok, action} <- extract_soap_action(doc),
         {:ok, response} <- process_soap_action(action, doc) do
      conn
      |> put_resp_content_type("text/xml")
      |> send_resp(200, build_soap_response(response))
    else
      {:error, reason} ->
        conn
        |> put_resp_content_type("text/xml")
        |> send_resp(500, build_soap_fault("Server", reason))
    end
  end

  defp extract_soap_action(doc) do
    try do
      # Extract the SOAP body action element
      action =
        doc
        |> xpath(
          ~x"//soap:Body/*[1]"
          |> add_namespace("soap", "http://schemas.xmlsoap.org/soap/envelope/")
        )

      if action do
        {:ok, action}
      else
        # Try SOAP 1.2 namespace
        action12 =
          doc
          |> xpath(
            ~x"//soap12:Body/*[1]"
            |> add_namespace("soap12", "http://www.w3.org/2003/05/soap-envelope")
          )

        if action12 do
          {:ok, action12}
        else
          {:error, "No SOAP action found in request body"}
        end
      end
    rescue
      e -> {:error, "Failed to extract SOAP action: #{inspect(e)}"}
    end
  end

  defp process_soap_action(action_element, doc) do
    # Extract operation name and parameters
    try do
      operation = xpath(action_element, ~x"local-name(.)"s)

      case operation do
        "GetUser" ->
          user_id = xpath(doc, ~x"//UserId/text()"s)
          handle_get_user(user_id)

        "CreateOrder" ->
          order_data = %{
            product_id: xpath(doc, ~x"//ProductId/text()"s),
            quantity: xpath(doc, ~x"//Quantity/text()"i),
            customer_name: xpath(doc, ~x"//CustomerName/text()"s)
          }
          handle_create_order(order_data)

        "ListProducts" ->
          category = xpath(doc, ~x"//Category/text()"s)
          handle_list_products(category)

        unknown ->
          {:error, "Unknown SOAP operation: #{unknown}"}
      end
    rescue
      e -> {:error, "Failed to process SOAP action: #{inspect(e)}"}
    end
  end

  # Example operation handlers
  defp handle_get_user(user_id) do
    {:ok, %{
      operation: "GetUserResponse",
      body: """
      <GetUserResponse xmlns="http://example.com/soap">
        <User>
          <Id>#{escape_xml(user_id)}</Id>
          <Name>John Doe</Name>
          <Email>john@example.com</Email>
        </User>
      </GetUserResponse>
      """
    }}
  end

  defp handle_create_order(order_data) do
    {:ok, %{
      operation: "CreateOrderResponse",
      body: """
      <CreateOrderResponse xmlns="http://example.com/soap">
        <OrderId>ORD-12345</OrderId>
        <Status>Created</Status>
        <ProductId>#{escape_xml(order_data.product_id)}</ProductId>
        <Quantity>#{order_data.quantity}</Quantity>
      </CreateOrderResponse>
      """
    }}
  end

  defp handle_list_products(category) do
    {:ok, %{
      operation: "ListProductsResponse",
      body: """
      <ListProductsResponse xmlns="http://example.com/soap">
        <Category>#{escape_xml(category)}</Category>
        <Products>
          <Product><Id>1</Id><Name>Widget A</Name></Product>
          <Product><Id>2</Id><Name>Widget B</Name></Product>
        </Products>
      </ListProductsResponse>
      """
    }}
  end

  defp build_soap_response(%{body: body}) do
    """
    <?xml version="1.0" encoding="UTF-8"?>
    <soap:Envelope xmlns:soap="http://schemas.xmlsoap.org/soap/envelope/">
      <soap:Header/>
      <soap:Body>
        #{body}
      </soap:Body>
    </soap:Envelope>
    """
  end

  defp build_soap_fault(fault_code, fault_string) do
    """
    <?xml version="1.0" encoding="UTF-8"?>
    <soap:Envelope xmlns:soap="http://schemas.xmlsoap.org/soap/envelope/">
      <soap:Body>
        <soap:Fault>
          <faultcode>soap:#{escape_xml(fault_code)}</faultcode>
          <faultstring>#{escape_xml(to_string(fault_string))}</faultstring>
        </soap:Fault>
      </soap:Body>
    </soap:Envelope>
    """
  end

  # Prevent XML injection in output
  defp escape_xml(string) when is_binary(string) do
    string
    |> String.replace("&", "&amp;")
    |> String.replace("<", "&lt;")
    |> String.replace(">", "&gt;")
    |> String.replace("\"", "&quot;")
    |> String.replace("'", "&apos;")
  end

  defp escape_xml(other), do: escape_xml(to_string(other))
end